const startInMinutes = Number.parseInt(body.start_in_minutes ?? body.startInMinutes ?? 5, 10);
const streamKey = String(body.stream_key ?? body.streamKey ?? "").trim();
const shellQuote = (value) => `'${String(value).replace(/'/g, `'"'"'`)}'`;

if (!topic) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "topic is required" };
    return [null, msg];
