    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "start_in_minutes must be a non-negative integer" };
    return [null, msg];
}
if (streamKey && !/^[A-Za-z0-9._-]+$/.test(streamKey)) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "stream_key may contain only letters, numbers, dot, underscore, and dash" };
    return [null, msg];
}

const args = [
    "zoom-provision-meeting",
    `--topic ${shellQuote(topic)}`,
    `--duration ${duration}`,
    `--start-in-minutes ${startInMinutes}`
];
if (streamKey) {
    args.push(`--stream-key ${shellQuote(streamKey)}`);
}
msg.payload = args.join(" ");
return [msg, null];

const body = (msg.payload && typeof msg.payload === "object") ? msg.payload : {};
const meetingId = String(body.meeting_id ?? body.meetingId ?? "").trim();
const displayName = String(body.display_name ?? body.displayName ?? body.topic ?? "Zoom Live").trim();
const shellQuote = (value) => `'${String(value).replace(/'/g, `'"'"'`)}'`;

if (!/^\d+$/.test(meetingId)) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
