    msg.payload = { error: "meeting_id must be a numeric Zoom meeting id" };
    return [null, msg];
}

msg.payload = [
    "zoom-stop-livestream",
    `--meeting-id ${meetingId}`
].join(" ");
return [msg, null];

const meetingId = String(msg.req?.params?.meetingId ?? "").trim();
if (!/^\d+$/.test(meetingId)) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: "meetingId must be a numeric Zoom meeting id" };
    return [null, msg];
}

msg.payload = [
    "zoom-get-livestream",
    `--meeting-id ${meetingId}`
].join(" ");
return [msg, null];

let data;
try {
    data = (typeof msg.payload === "string") ? JSON.parse(msg.payload) : msg.payload;
} catch (err) {
    msg.statusCode = 502;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = {
        error: "Zoom CLI returned invalid JSON",
        raw: typeof msg.payload === "string" ? msg.payload : JSON.stringify(msg.payload ?? null),
        details: err.message
    };
    return [null, msg];
}

msg.statusCode = 200;
msg.headers = { "Content-Type": "application/json" };
msg.payload = data;
return [msg, null];

const raw = typeof msg.payload === "string" ? msg.payload.trim() : JSON.stringify(msg.payload ?? null);
let rc = msg.rc;
if (rc && typeof rc === "object" && Object.prototype.hasOwnProperty.call(rc, "code")) {
    rc = rc.code;
}
msg.statusCode = msg.statusCode || (Number.isInteger(rc) && rc !== 0 ? 502 : 500);
msg.headers = { "Content-Type": "application/json" };
msg.payload = {
    error: msg.payload?.error || "Zoom control command failed",
    rc: rc ?? null,
    output: raw || null
};
return msg;
